export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    if (url.pathname === "/health") {
      return json({ service: "gateway-worker", ok: true });
    }

    if (url.pathname.startsWith("/api/users")) {
      return forwardToService(env.USERS_SERVICE, request, "/internal/users");
    }

    if (url.pathname.startsWith("/api/orders")) {
      return forwardToService(env.ORDERS_SERVICE, request, "/internal/orders");
    }

    if (url.pathname === "/api/composite/user-orders" && request.method === "GET") {
      const userId = url.searchParams.get("userId");
      if (!userId) {
        return json({ error: "userId is required" }, 400);
      }

      const userReq = new Request(`https://users.internal/internal/users/${encodeURIComponent(userId)}`, {
        method: "GET",
        headers: request.headers
      });

      const ordersReq = new Request(`https://orders.internal/internal/orders?userId=${encodeURIComponent(userId)}`, {
        method: "GET",
        headers: request.headers
      });

      const [userRes, ordersRes] = await Promise.all([
        env.USERS_SERVICE.fetch(userReq),
        env.ORDERS_SERVICE.fetch(ordersReq)
      ]);

      const userBody = await safeJson(userRes);
      const ordersBody = await safeJson(ordersRes);

      return json({
        user: userBody,
        orders: ordersBody
      }, userRes.ok && ordersRes.ok ? 200 : 502);
    }

    return json({ error: "Not found" }, 404);
  }
};

async function forwardToService(service, request, internalPrefix) {
  const incomingUrl = new URL(request.url);
  const suffix = incomingUrl.pathname.replace(/^\/api\/(users|orders)/, "");
  const targetUrl = new URL(`https://internal.example${internalPrefix}${suffix}`);
  targetUrl.search = incomingUrl.search;

  const headers = new Headers(request.headers);
  headers.set("x-forwarded-by", "gateway-worker");

  const init = {
    method: request.method,
    headers,
    body: canHaveBody(request.method) ? request.body : undefined,
    redirect: "manual"
  };

  return service.fetch(new Request(targetUrl.toString(), init));
}

function canHaveBody(method) {
  return !["GET", "HEAD"].includes(method.toUpperCase());
}

function json(data, status = 200, headers = {}) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      "content-type": "application/json; charset=utf-8",
      ...headers
    }
  });
}

async function safeJson(response) {
  const text = await response.text();
  try {
    return JSON.parse(text);
  } catch {
    return { raw: text, status: response.status };
  }
}

