const users = new Map([
  ["1", { id: "1", name: "Ada Lovelace", tier: "pro" }],
  ["2", { id: "2", name: "Grace Hopper", tier: "enterprise" }],
  ["3", { id: "3", name: "Linus Torvalds", tier: "free" }]
]);

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    if (url.pathname === "/health") {
      return json({ service: "users-worker", ok: true });
    }

    if (!url.pathname.startsWith("/internal/users")) {
      return json({ error: "Not found" }, 404);
    }

    if (request.method === "GET" && url.pathname === "/internal/users") {
      return json({
        items: [...users.values()]
      });
    }

    if (request.method === "GET" && /^\/internal\/users\/[^/]+$/.test(url.pathname)) {
      const id = decodeURIComponent(url.pathname.split("/").pop());
      const user = users.get(id);

      if (!user) {
        return json({ error: "User not found" }, 404);
      }

      const includeOrders = url.searchParams.get("includeOrders") === "true";
      if (!includeOrders) {
        return json(user);
      }

      const ordersReq = new Request(`https://orders.internal/internal/orders?userId=${encodeURIComponent(id)}`, {
        method: "GET",
        headers: request.headers
      });

      const ordersRes = await env.ORDERS_SERVICE.fetch(ordersReq);
      const orders = await safeJson(ordersRes);

      return json({
        ...user,
        orders
      });
    }

    if (request.method === "POST" && url.pathname === "/internal/users") {
      const body = await request.json().catch(() => null);
      if (!body?.id || !body?.name) {
        return json({ error: "id and name are required" }, 400);
      }

      const user = {
        id: String(body.id),
        name: String(body.name),
        tier: body.tier ? String(body.tier) : "free"
      };

      users.set(user.id, user);
      return json(user, 201);
    }

    return json({ error: "Not found" }, 404);
  }
};

function json(data, status = 200, headers = {}) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      "content-type": "application/json; charset=utf-8",
      ...headers
    }
  });
}

async function safeJson(response) {
  const text = await response.text();
  try {
    return JSON.parse(text);
  } catch {
    return { raw: text, status: response.status };
  }
}

