const orders = [
  { id: "o-100", userId: "1", total: 125.5, status: "paid" },
  { id: "o-101", userId: "1", total: 42.0, status: "shipped" },
  { id: "o-102", userId: "2", total: 560.99, status: "processing" },
  { id: "o-103", userId: "3", total: 12.49, status: "paid" }
];

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    if (url.pathname === "/health") {
      return json({ service: "orders-worker", ok: true });
    }

    if (!url.pathname.startsWith("/internal/orders")) {
      return json({ error: "Not found" }, 404);
    }

    if (request.method === "GET" && url.pathname === "/internal/orders") {
      const userId = url.searchParams.get("userId");
      const items = userId ? orders.filter((o) => o.userId === userId) : orders;
      return json({ items });
    }

    if (request.method === "GET" && /^\/internal\/orders\/[^/]+$/.test(url.pathname)) {
      const id = decodeURIComponent(url.pathname.split("/").pop());
      const order = orders.find((o) => o.id === id);

      if (!order) {
        return json({ error: "Order not found" }, 404);
      }

      return json(order);
    }

    if (request.method === "POST" && url.pathname === "/internal/orders") {
      const body = await request.json().catch(() => null);
      if (!body?.id || !body?.userId || typeof body?.total !== "number") {
        return json({ error: "id, userId, and numeric total are required" }, 400);
      }

      const order = {
        id: String(body.id),
        userId: String(body.userId),
        total: body.total,
        status: body.status ? String(body.status) : "processing"
      };

      orders.push(order);
      return json(order, 201);
    }

    return json({ error: "Not found" }, 404);
  }
};

